import React, { useState } from 'react';
import axios from 'axios';

function App() {
  const [form, setForm] = useState({
    clinic_id: 1,
    patient_name: '',
    patient_phone: '',
    channel: 'whatsapp',
    description: '',
    attachment_url: '',
    criticality: 'media'
  });

  const handleSubmit = async (e) => {
    e.preventDefault();

    try {
      await axios.post('http://localhost:3001/complaints', form);
      alert('Reclamação cadastrada!');
    } catch (error) {
      alert('Erro ao salvar');
    }
  };

  return (
    <div style={{ padding: 40 }}>
      <h2>Cadastro de Reclamação</h2>

      <form onSubmit={handleSubmit}>
        <input placeholder="Nome" onChange={e => setForm({...form, patient_name: e.target.value})} /><br/><br/>
        <input placeholder="Telefone" onChange={e => setForm({...form, patient_phone: e.target.value})} /><br/><br/>

        <select onChange={e => setForm({...form, channel: e.target.value})}>
          <option value="whatsapp">WhatsApp</option>
          <option value="google">Google</option>
          <option value="facebook">Facebook</option>
        </select><br/><br/>

        <textarea placeholder="Descrição" onChange={e => setForm({...form, description: e.target.value})}></textarea><br/><br/>

        <button type="submit">Salvar</button>
      </form>
    </div>
  );
}

export default App;
